/**
 * granulare ACL-rechte fuer die custom-event-entitaet (s4gtm_event).
 *
 * ohne dieses mapping ist die ueber die admin-api zugaengliche entitaet nur fuer administratoren
 * schreibbar. das mapping legt eine eigene rechte-karte an, sodass shop-betreiber rollen granular
 * vergeben koennen (lesen / bearbeiten / anlegen / loeschen). die konfigurations-/event-seiten bleiben
 * zusaetzlich hinter "system.system_config" gegated (siehe module/index.js, routes-meta).
 */
Shopware.Service('privileges').addPrivilegeMappingEntry({
    category: 'permissions',
    parent: null,
    key: 's4gtm_event',
    roles: {
        viewer: {
            privileges: [
                's4gtm_event:read',
                's4gtm_event_sales_channel:read',
                'sales_channel:read',
            ],
            dependencies: [],
        },
        editor: {
            privileges: [
                's4gtm_event:update',
                's4gtm_event_sales_channel:create',
                's4gtm_event_sales_channel:delete',
            ],
            dependencies: [
                's4gtm_event.viewer',
            ],
        },
        creator: {
            privileges: [
                's4gtm_event:create',
            ],
            dependencies: [
                's4gtm_event.viewer',
                's4gtm_event.editor',
            ],
        },
        deleter: {
            privileges: [
                's4gtm_event:delete',
            ],
            dependencies: [
                's4gtm_event.viewer',
            ],
        },
    },
});
